function formatDate(date){
  return convertDateTimeTZ(date , 'Africa/Dar_es_salaam')
}

function convertDateTimeTZ(date, tzString) {
  return new Date(
    (typeof date === "string" ? new Date(date) : date).toLocaleString("en-US", {
      timeZone: tzString,
    })
  );
}
var globalIpAddress;

function InsertAuditTrail(
  user_id,
  event_type,
  new_body,
  api_router,
  browser_used,
  rollId,
  message,
  ip_address,
  tableId
) {
  console.log(JSON.stringify(new_body));
  db.query(
    "INSERT INTO audit_trail (user_id, event_type, new_body, " +
      "created_at, ip_address, api_router, browser_used, rollId, message, tableName) " +
      "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
    [
      user_id,
      event_type,
      JSON.stringify(new_body),
      new Date(),
      ip_address,
      api_router,
      browser_used,
      rollId,
      message,
      tableId,
    ],
    (err, result) => {
      if (err) {
        console.log(err);
        return {
          error: true,
          statusCode: 400,
          message: err,
        };
      }
      return "sent";
      // return ({
      // error:false,
      // statusCode: 300,
      // message: 'The user has been registerd with us!'
      // });
    }
  );
}

function UpdateAuditTrail(
  user_id,
  event_type,
  new_body,
  api_router,
  browser_used,
  rollId,
  message,
  ip_address,
  old_body,
  tableId
) {
  // console.log(JSON.stringify(new_body))
  db.query(
    "INSERT INTO audit_trail (user_id, event_type, new_body, " +
      "created_at, ip_address, api_router, browser_used, rollId, message, old_body, tableName) " +
      "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
    [
      user_id,
      event_type,
      JSON.stringify(new_body),
      new Date(),
      ip_address,
      api_router,
      browser_used,
      rollId,
      message,
      JSON.stringify(old_body),
      tableId,
    ],
    (err, result) => {
      if (err) {
        console.log(err);
        return {
          error: true,
          statusCode: 400,
          message: err,
        };
      }
      return "sent";
      // return ({
      // error:false,
      // statusCode: 300,
      // message: 'The user has been registerd with us!'
      // });
    }
  );
}

