router.post("/futauser", makundiValidation, (req, res, next) => {
  if (
    !req.headers.authorization ||
    !req.headers.authorization.startsWith("Bearer") ||
    !req.headers.authorization.split(" ")[1]
  ) {
    return res.status(200).json({
      error: true,
      statusCode: 422,
      message: "No access to end point",
    });
  }
  const theToken = req.headers.authorization.split(" ")[1];
  const decoded = jwt.verify(theToken, "the-super-strong-secrect");
  db.query(
    `UPDATE staffs SET user_status = 0 WHERE id = ${db.escape(req.body.name)}`,
    function (error, results, fields) {
      if (error) {
        console.log(error);
      }
      UpdateAuditTrail(
        decoded.id,
        "updated",
        req.body,
        req.url,
        req.body.browser_used,
        req.body.name,
        "The user has been deleted with us!",
        req.body.ip_address,
        "",
        "staffs"
      );
      return res.send({
        error: false,
        statusCode: 300,
        message: "Fee Successfully Recorded.",
      });
    }
  );
});

