router.post("/verify", signupValidation, (req, res, next) => {
  console.log(req.body);
  db.query(
    `SELECT * FROM staffs WHERE LOWER(secure_token) = LOWER(${db.escape(
      req.body.TrackingNumber
    )});`,
    (err, result) => {
      console.log(result);
      if (result.length <= 0) {
        return res.status(200).send({
          error: true,
          statusCode: 306,
          message: "Taarifa sio sahihi!",
        });
      } else {
        // username is available
        db.query(
          `update staffs SET user_status = '1', secure_token = 0 WHERE secure_token = ${db.escape(
            req.body.TrackingNumber
          )}`,
          (err, result) => {
            if (err) {
              console.log(err);
              return res.status(400).send({
                error: true,
                statusCode: 400,
                message: err,
              });
            }
            return res.status(200).send({
              error: false,
              statusCode: 300,
              message: "Mtumiaji amethibitishwa!",
            });
          }
        );
      }
    }
  );
});

