router.post("/addRole", shirikishoValidation, (req, res, next) => {
  var permission_list = req.body.permissions;
  if (
    !req.headers.authorization ||
    !req.headers.authorization.startsWith("Bearer") ||
    !req.headers.authorization.split(" ")[1]
  ) {
    return res.status(200).json({
      error: true,
      statusCode: 422,
      message: "No access to end point",
    });
  }
  const theToken = req.headers.authorization.split(" ")[1];
  const decoded = jwt.verify(theToken, "the-super-strong-secrect");
  db.query(
    `SELECT count(*) as kaunti FROM role_management where 
    role_name = ${db.escape(req.body.roleName)} and status_id = 1`,
    function (error, results, fields) {
      if (error) {
        console.log(error);
      }
      if (results[0].kaunti <= 0) {
        db.query(
          `INSERT INTO role_management (role_name, status_id) VALUES 
    (${db.escape(req.body.roleName)}, 1)`,
          function (error, results, fields) {
            if (error) res.send({ error: true, message: "Zoni haijasajiliwa" });
            db.query(
              `SELECT id FROM role_management where role_name = ${db.escape(
                req.body.roleName
              )}`,
              function (error, results, fields) {
                if (error) {
                  console.log(error);
                }
                var rollId = results[0].id;
                var splitted_perm = permission_list.toString().split(",");
                for (var i = 0; i < splitted_perm.length; i++) {
                  splitted_perm[i] = splitted_perm[i]
                    .replace(/^\s*/, "")
                    .replace(/\s*$/, "");
                  // Add additional code here, such as:
                  console.log(splitted_perm[i]);
                  db.query(
                    `INSERT INTO permission_role (permission_id, role_id, status_id) VALUES 
            (${db.escape(req.body.permissions[i])}, ${db.escape(rollId)}, 1)`,
                    function (error1, results1, fields1) {
                      if (error1) {
                        console.log(error1);
                      }
                    }
                  );
                }
                InsertAuditTrail(
                  decoded.id,
                  "created",
                  req.body,
                  req.url,
                  req.body.browser_used,
                  rollId,
                  "Zoni/Kanda imesajiliwa!",
                  req.body.ip_address,
                  "role_management"
                );
              }
            );
            return res.send({
              error: false,
              statusCode: 300,
              data: { status: "sucess" },
              message: "Zoni imesajiliwa.",
            });
          }
        );
      } else {
        return res.send({
          error: false,
          statusCode: 306,
          data: { status: "sucess" },
          message: "Imeshindwa kusajili, Role ilishasajiliwa.",
        });
      }
    }
  );
});

