//register application categories api
router.post("/register-application", makundiValidation, (req, res, next) => {
  console.log(req.body);
  db.query(
    `SELECT * FROM application_categories WHERE LOWER(app_name) = LOWER(${db.escape(
      req.body.app_name
    )});`,
    (err, result) => {
      if (result.length) {
        return res.status(200).send({
          error: true,
          statusCode: 306,
          msg: "This app is already in use!",
        });
      } else {
        // username is available
        bcrypt.hash(req.body.app_name, 10, (err, hash) => {
          if (err) {
            return res.status(500).send({
              error: true,
              statusCode: 500,
              message: err,
            });
          } else {
            // has hashed pw => add to database
            db.query(
              `INSERT INTO application_categories (app_name, secure_token) VALUES (
            ${db.escape(req.body.app_name)}, ${db.escape(hash)})`,
              (err, result) => {
                if (err) {
                  console.log(err);
                  return res.status(400).send({
                    error: true,
                    statusCode: 400,
                    message: err,
                  });
                }
                return res.status(200).send({
                  error: false,
                  statusCode: 300,
                  message: "The app has been registerd with us!",
                });
              }
            );
          }
        });
      }
    }
  );
});

