//update mwombaji api
router.post("/update-applicant", signupValidation, (req, res, next) => {
  // console.log(req.body)
  db.query(
    `SELECT * FROM users WHERE LOWER(email) = LOWER(${db.escape(
      req.body.username
    )});`,
    (err, result) => {
      console.log(result);
      if (result.length <= 0) {
        return res.status(200).send({
          error: true,
          statusCode: 306,
          msg: "Imeshindwa kumtambua mtumiaji!",
        });
      } else {
        // username is available
        bcrypt.hash(req.body.password, 10, (err, hash) => {
          if (err) {
            return res.status(500).send({
              error: true,
              statusCode: 500,
              message: err,
            });
          } else {
            // has hashed pw => add to database
            if ((req.body.password = "0")) {
              console.log("mojamioja");
              db.query(
                "UPDATE users SET email = ?, name = ? WHERE id = ?",
                [req.body.email, req.body.name, req.body.userId],
                (err, result) => {
                  if (err) {
                    console.log(err);
                    return res.status(400).send({
                      error: true,
                      statusCode: 400,
                      message: err,
                    });
                  }
                  return res.status(200).send({
                    error: false,
                    statusCode: 300,
                    message: "The user has been updated!",
                  });
                }
              );
            } else {
              console.log("mbilimbli");
              db.query(
                "UPDATE users SET email = ?, password = ?, name = ? WHERE id = ?",
                [req.body.email, hash, req.body.name, req.body.userId],
                (err, result) => {
                  if (err) {
                    console.log(err);
                    return res.status(400).send({
                      error: true,
                      statusCode: 400,
                      message: err,
                    });
                  }
                  return res.status(200).send({
                    error: false,
                    statusCode: 300,
                    message: "The user has been updated!",
                  });
                }
              );
            }
          }
        });
      }
    }
  );
});

//register api
router.post("/delete-user", signupValidation, (req, res, next) => {
  // has hashed pw => add to database
  db.query(
    `UPDATE users SET user_status = 0 WHERE email = ${db.escape(
      req.body.email
    )},`,
    (err, result) => {
      if (err) {
        console.log(err);
        return res.status(400).send({
          error: true,
          statusCode: 400,
          message: err,
        });
      }
      return res.status(200).send({
        error: false,
        statusCode: 300,
        message: "The user has been deleted!",
      });
    }
  );
});



