//get list of users
router.get("/vyeolist", signupValidation, (req, res, next) => {
  var obj = [];
  var obj1 = [];
  if (
    !req.headers.authorization ||
    !req.headers.authorization.startsWith("Bearer") ||
    !req.headers.authorization.split(" ")[1]
  ) {
    return res.status(422).json({
      error: true,
      statusCode: 422,
      message: "No access to end point",
    });
  }
  const theToken = req.headers.authorization.split(" ")[1];
  const decoded = jwt.verify(theToken, "the-super-strong-secrect");
  db.query(
    `SELECT vyeo.id as vyeoId, roles.id as rolesId,
      roles.name as name, vyeo.rank_name as role_name FROM roles, 
      vyeo where vyeo.id = roles.vyeoId and roles.status_id = 1`,
    function (error, results, fields) {
      if (error) {
        console.log(error);
      }
      for (var i = 0; i < results.length; i++) {
        var vyeoName = results[i].vyeoName;
        var rolesId = results[i].rolesId;
        var name = results[i].name;
        var role_name = results[i].role_name;
        var vyeoId = results[i].vyeoId;
        obj.push({
          vyeoName: vyeoName,
          rolesId: rolesId,
          name: name,
          roleId: vyeoId,
          role: role_name,
          vyeoId: vyeoId,
        });
      }
      db.query(
        "SELECT vyeo.id as vyeoId, " +
          " vyeo.rank_name as role_name, rank_level FROM " +
          " vyeo where status_id = ?",
        [1],
        function (error1, results1, fields1) {
          if (error1) {
            console.log(error1);
          }
          for (var i = 0; i < results1.length; i++) {
            var role_name = results1[i].role_name;
            var vyeoId = results1[i].vyeoId;
            var rank_level = results1[i].rank_level;
            obj1.push({
              roleExist: role_name,
              vyeoIdExist: vyeoId,
              vyeoLocation: rank_level,
            });
          }
          return res.send({
            error: false,
            statusCode: 300,
            data: obj,
            vyeo: obj1,
            message: "Fetch Successfully.",
          });
        }
      );
    }
  );
});

