router.post("/changepass", (req, res, next) => {
  // console.log(req.body.browser_used)
  if (
    !req.headers.authorization ||
    !req.headers.authorization.startsWith("Bearer") ||
    !req.headers.authorization.split(" ")[1]
  ) {
    return res.status(200).json({
      error: true,
      statusCode: 422,
      message: "No access to end point",
    });
  }
  const theToken = req.headers.authorization.split(" ")[1];
  const decoded = jwt.verify(theToken, "the-super-strong-secrect");
  var obj = [];
  var objRM = [];
  db.query(
    `SELECT staffs.id as id, password, staffs.name as name, 
    staffs.username as username, staffs.phone_no as phone_no, 
    staffs.user_status as user_status, staffs.last_login as last_login, 
    staffs.role_id as role_id, staffs.email as email,
    staffs.station_level as station_level, user_level, staffs.office as office, 
    vyeo.rank_name as rank_name, 
    vyeo.status_id as status_id, vyeo.rank_level as rank_level, twofa
    FROM staffs, vyeo WHERE staffs.user_level = vyeo.id AND 
    staffs.id = ${db.escape(req.body.userid)} AND 
    user_status = 1;`,
    (err, result) => {
      // user does not exists
      if (err) {
        console.log(err);
        return res.status(400).send({
          error: true,
          statusCode: 400,
          message: err,
        });
      }
      if (!result.length) {
        // if()
        return res.status(200).send({
          error: true,
          statusCode: 302,
          message: "Username or password is incorrect!",
        });
      }
      // check password
      bcrypt.compare(
        req.body.oldpassword,
        result[0]["password"],
        (bErr, bResult) => {
          // wrong password
          if (bErr) {
            console.log(bErr);
            return res.status(200).send({
              error: true,
              statusCode: 302,
              message: "old password not valid, please try again!",
            });
          }
          if (bResult) {
            bcrypt.hash(req.body.password, 10, (err, hash) => {
              if (err) {
                return res.status(500).send({
                  error: true,
                  statusCode: 500,
                  message: err,
                });
              } else {
                const random_WithFiftySymbols = crypto
                  .randomBytes(50)
                  .toString("hex");
                var secr_tokn = random_WithFiftySymbols;

                // has hashed pw => add to database
                db.query(
                  `UPDATE staffs SET password =  ${db.escape(
                    hash
                  )} WHERE id = ${db.escape(req.body.userid)}`,
                  (err, result) => {
                    if (err) {
                      console.log(err);
                      return res.status(400).send({
                        error: true,
                        statusCode: 400,
                        message: err,
                      });
                    }
                    // db.query(`SELECT id FROM staffs where id = ${db.escape(req.body.userId)}`,
                    // function (error, results, fields) {
                    //     if (error) {console.log(error)}
                    var rollId = req.body.userId;
                    var req_body = {
                      userid: req.body.userId,
                      oldpassword: "********",
                      newpassword: "********",
                    };
                    InsertAuditTrail(
                      decoded.id,
                      "updated",
                      req_body,
                      req.url,
                      req.body.browser_used,
                      rollId,
                      "The user has been registerd with us!",
                      req.body.ip_address,
                      "staffs"
                    );
                    // });
                    return res.status(200).send({
                      error: false,
                      statusCode: 300,
                      message: "Password changed succesfully!",
                    });
                  }
                );
              }
            });
          } else {
            return res.status(200).send({
              error: true,
              statusCode: 302,
              message: "Data is incorrect!",
            });
          }
        }
      );
    }
  );
});

