  //     }else{
  //         var token_id = results[0].token_id;
  //         console.log("token_id " + token_id)
  //         if(token_id != 0){
  db.query(
    "SELECT id, app_name, secure_token FROM application_categories",
    function (error, results, fields) {
      if (error) {
        console.log(error);
      }
      for (var i = 0; i < results.length; i++) {
        var categoryId = results[i].id;
        var categoryName = results[i].app_name;
        var categoryCode = results[i].secure_token;
        obj.push({
          categoryId: categoryId,
          categoryName: categoryName,
          categoryCode: categoryCode,
        });
      }

      return res.send({
        error: false,
        statusCode: 300,
        data: obj,
        message: "List of categories.",
      });
    }
  );
  // }else if(token_id == 0){
