            var minutes = Math.floor((diffInSeconds / 60) % 60);
            var seconds = Math.floor(diffInSeconds % 60);
            var milliseconds = Math.round(
              (diffInSeconds - Math.floor(diffInSeconds)) * 1000
            );

            var remain_days;
