function sendMail(staff_id) {
  db.query(
    "select email from staffs where id = ?",
    [req.body.staffs],
    function (error, results, fields) {
      if (error) {
        console.log(error);
      }
      var email = results[0].email;
      let transporter = nodeMailer.createTransport({
        host: process.env.MAIL_HOST,
        port: 465,
        secure: true,
        auth: {
          user: process.env.MAIL_USER,
          pass: process.env.MAIL_PASS,
        },
      });
      let mailOptions = {
        from: '"Ithibati ya Usajili" <noreply@codebiz.co.tz>', // sender address
        to: email, // list of receivers
        subject: "Taarifa ya Ombi", // Subject line
        text:
          "Ombi la Kuanzisha shule lenye namba " +
          req.body.trackerId +
          " limetumwa kwako. Asante", // plain text body
        html:
          "Ombi la Kuanzisha shule lenye namba <b>" +
          req.body.trackerId +
          "</b> limetumwa kwako. Asante", // html body
      };

      transporter.sendMail(mailOptions, (error, info) => {
        if (error) {
          return console.log(error);
        }
        console.log("Message %s sent: %s", info.messageId, info.response);
        // res.render('index');
        return res.status(200).send({
          error: true,
          statusCode: 300,
          msg: "Mail imetumwa!!!",
        });
      });
    }
  );
}

