              var approved_at = results[i].updated_at;
              var LgaName = results[i].LgaName;
              var RegionName = results[i].RegionName;
              var tracking_number = results[i].tracking_number;
              var WardName = results[i].WardName;
              var reg_no = results[i].registration_number;
              var dateDisplay;
              if (approved_at != null) {
                approved_at = dateandtime.format(approved_at, "DD/MM/YYYY");
                // dateDisplay = dateandtime.format(approved_at, 'DD-MM-YYYY');
              }
              // prints date & time in YYYY-MM-DD HH:MM:SS format
