router.post("/register-applications", makundiValidation, (req, res, next) => {
  if (
    !req.headers.authorization ||
    !req.headers.authorization.startsWith("Bearer") ||
    !req.headers.authorization.split(" ")[1]
  ) {
    return res.status(200).json({
      error: true,
      statusCode: 422,
      message: "No access to end point",
    });
  }
  const theToken = req.headers.authorization.split(" ")[1];
  const decoded = jwt.verify(theToken, "the-super-strong-secrect");
  db.query(
    `INSERT INTO applications (applicationName, applicationCode, created_by) VALUES (${db.escape(
      req.body.name
    )}, ${db.escape(req.body.code)}, '${decoded.id}')`,
    function (error, results, fields) {
      if (error) {
        console.log(error);
      }
      return res.send({
        error: false,
        statusCode: 300,
        data: results[0],
        message: "Fee Successfully Recorded.",
      });
    }
  );
});

