router.post("/scantrack", shirikishoValidation, (req, res, next) => {
  // console.log(req.body)
  var objMaoni = [];
  var trackingNo = req.body.trackingNo;
  if (
    !req.headers.authorization ||
    !req.headers.authorization.startsWith("Bearer") ||
    !req.headers.authorization.split(" ")[1]
  ) {
    return res.status(200).json({
      error: true,
      statusCode: 422,
      message: "No access to end point",
    });
  }
  const theToken = req.headers.authorization.split(" ")[1];
  const decoded = jwt.verify(theToken, "the-super-strong-secrect");
  db.query(
    "SELECT rank_name, is_approved, app_name FROM applications, vyeo, application_categories WHERE " +
      " vyeo.id = applications.status_id AND tracking_number = ? " +
      " AND application_categories.id = applications.application_category_id",
    [trackingNo],
    function (error, results, fields) {
      if (error) res.send({ error: true, message: "Namba ya ombi haipo" });
      if (results.length > 0) {
        var rank_name = results[0].rank_name;
        var is_approved = results[0].is_approved;
        var app_name = results[0].app_name;
        var status_say;
        if (is_approved == 0) {
          status_say =
            "Aina ya Ombi " + app_name + " lipo kwa " + rank_name + ".";
        }
        if (is_approved == 1) {
          status_say =
            "Aina ya Ombi " + app_name + " lipo kwa " + rank_name + ".";
        }
        if (is_approved == 2) {
          status_say = "Ombi Limekamilika";
        }
        if (is_approved == 3) {
          status_say = "Ombi Limekataliwa";
        }
        db.query(
          "SELECT name, user_from, user_to, coments, maoni.created_at as created_at, rank_name " +
            " from maoni, staffs, vyeo WHERE staffs.id = maoni.user_to AND vyeo.id = staffs.user_level " +
            " AND trackingNo = ? ORDER BY maoni.id DESC LIMIT 1",
          [trackingNo],
          function (error, results, fields) {
            if (error) {
              console.log(results);
            }

            // for(var i = 0; i < results.length; i++){
            if (results.length > 0) {
              var name = results[0].name;
              var user_from = results[0].user_from;
              var user_to = results[0].user_to;
              var coments = results[0].coments;
              var maoniTime = results[0].created_at;
              var rank_name = results[0].rank_name;
            } else {
              var name = "";
              var user_from = "";
              var user_to = "";
              var coments = "";
              var rank_name = "";
            }
            if (maoniTime == null) {
              maoniTime = new Date();
            }
            // console.log(maoniTime)
            maoniTime = dateandtime.format(maoniTime, "DD/MM/YYYY hh:mm:ss");
            objMaoni.push({
              user_from: user_from,
              name: name,
              user_to: user_to,
              coments: coments,
              created_at: maoniTime,
              rank_name: rank_name,
            });
            // }
            if (error)
              res.send({ error: true, message: "Namba ya ombi haipo" });
            return res.send({
              error: false,
              statusCode: 300,
              message: status_say,
              jina: name,
            });
          }
        );
      } else {
        return res.send({
          error: false,
          statusCode: 300,
          message: "Namba ya Ombi Haipo.",
        });
      }
    }
  );
});

