router.post("/wezesha2fa", shirikishoValidation, (req, res, next) => {
  // console.log(req.body)
  var twfa = req.body.faValue;
  if (twfa == 0) {
    twfa = false;
  }
  if (twfa == 1) {
    twfa = true;
  }
  if (
    !req.headers.authorization ||
    !req.headers.authorization.startsWith("Bearer") ||
    !req.headers.authorization.split(" ")[1]
  ) {
    return res.status(200).json({
      error: true,
      statusCode: 422,
      message: "No access to end point",
    });
  }
  const theToken = req.headers.authorization.split(" ")[1];
  const decoded = jwt.verify(theToken, "the-super-strong-secrect");
  db.query(
    `UPDATE staffs SET twofa = ${twfa} WHERE id = ${decoded.id}`,
    function (error, results, fields) {
      if (error) {
        console.log(error);
        res.send({ error: true, message: "Mabadiliko hayajafanikiwa" });
      } else {
        return res.send({
          error: false,
          statusCode: 300,
          message: "Mabadiliko Yamefanikiwa",
        });
      }
    }
  );
});

router.post("/thibitisha2fa", shirikishoValidation, (req, res, next) => {
  // console.log(req.body)
  var twfa = req.body.faValue;
  if (
    !req.headers.authorization ||
    !req.headers.authorization.startsWith("Bearer") ||
    !req.headers.authorization.split(" ")[1]
  ) {
    return res.status(200).json({
      error: true,
      statusCode: 422,
      message: "No access to end point",
    });
  }
  const theToken = req.headers.authorization.split(" ")[1];
  const decoded = jwt.verify(theToken, "the-super-strong-secrect");
  db.query(
    `SELECT twofa_digit
        FROM staffs WHERE id = ${db.escape(decoded.id)};`,
    (err, result) => {
      if (err) {
        res.send({ err: true, message: "Verification haiyajafanikiwa" });
      }
      if (result[0].twofa_digit == twfa) {
        db.query(
          `UPDATE staffs SET twofa_digit = 0 WHERE id = ${decoded.id}`,
          function (error, results, fields) {
            if (error) {
              res.send({ error: true, message: "Mabadiliko hayajafanikiwa" });
            } else {
              return res.send({
                error: false,
                statusCode: 300,
                message: "Amefanikiwa Kuingia",
              });
            }
          }
        );
      } else {
        return res.send({
          error: false,
          statusCode: 301,
          message: "Msimbo sio Sahihi",
        });
      }
    }
  );
});

